package com.wherefood.domain;
import jakarta.persistence.*; import java.time.*; import java.util.*;
@Entity @Table(name="places") public class Place { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) public Long id; @Column(nullable=false) public String name; public String address; @Column(name="source_url") public String sourceUrl; @Column(name="maps_url") public String mapsUrl; @Enumerated(EnumType.STRING) public PlaceStatus status=PlaceStatus.PENDING; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="category_id") public Category category; @ManyToMany @JoinTable(name="place_highlight_tags", joinColumns=@JoinColumn(name="place_id"), inverseJoinColumns=@JoinColumn(name="tag_id")) public Set<HighlightTag> highlightTags = new LinkedHashSet<>(); @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="created_by") public User createdBy; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="updated_by") public User updatedBy; public Instant deactivatedAt; public Instant createdAt; public Instant updatedAt; }
